    "目标": "空腹血糖<7 mmol/L，餐后<10 mmol/L；血压<130/85 mmHg；体重稳定（个体化目标需医生确认）",
    "记录要求": "使用纸质/电子日记记录日期、时间、数值、饮食运动情况，下次复诊时携带供医生分析。"
  },
  "风险分层": {
    "级别": "中高风险",
    "依据": ["血糖控制未达标（HbA1c>8.5%）", "存在周围神经病变症状（足麻木）", "用药依从性问题"]
  },
  "随访建议": {
